var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이수연!","JPN":"カナミ！","ENG":"Lee Sooyeon!","TWN":"李秀妍！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_SF"},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저도 확인했습니다! 신성반응 관측!","JPN":"こちらも確認しました！　神聖反応観測！","ENG":"I sensed it too! Divinity Response confirmed!","TWN":"我也有確認到神聖反應！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제 6종 침식체입니다!","JPN":"第6種侵食体です！","ENG":"It's a Category 6 Corrupted Object!","TWN":"是6類侵蝕體！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너무 빨라! 어떻게 벌써 나타난 거지?!","JPN":"早すぎる！　どうして今現れたんだ！？","ENG":"But it’s too early! How did it get here?!","TWN":"這麼快！怎麼會這麼快就出現？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"모릅니다! 각지에 차원 균열 발생!","JPN":"わかりません！　各地で次元の亀裂が発生！","ENG":"I don’t know! Multiple dimensional rifts are appearing!","TWN":"不知道！到處都在發生次元裂縫！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이대로 두면 허수차원에 떠돌던 다른 6종 침식체들도 모두 모여들 겁니다!","JPN":"このままでは虚数次元にいる他の第6種侵食体まで集まってきます！","ENG":"If we don’t close them now, other Category 6 C.O.s from the Imaginary Dimension will try to come in as well!","TWN":"這樣下去，其他在虛空次元的6類侵蝕體也會跑到這裡來的！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"드래곤 버스터 준비시켜! 당장 나간다!","JPN":"ドラゴンバスターを用意しろ！　直ちに向かう！","ENG":"Ready the Dragon Buster! I’m going out now!","TWN":"準備屠龍者！立刻出發！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"혼자서는 무리에요! 스승님도 아직 구속이 완전히 풀리지 않았잖아요!","JPN":"一人では無理です！　師匠もまだ拘束が完全には解けていないでしょう！","ENG":"You can’t go by yourself! Your restrainers are not fully released yet!","TWN":"師父自己是要去送死嗎！你也還沒完全解開拘束！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"상관없어! 아직 하나만 나타났을 때 어떻게든 잡아야 해!","JPN":"構わん！　まだ1体のうちに、なんとしても阻止しないと！","ENG":"I don’t care! We have to kill it while there’s only one!","TWN":"沒關係！總之一定要攔住他！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"자칫하면 게임이 시작하기도 전에 세상이 붕괴될 거다!","JPN":"下手したらゲームが始まる前に世界が崩壊するぞ！","ENG":"Otherwise we will lose this world even before the game starts!","TWN":"萬一有什麼差池，世界很能會在遊戲開始前就崩潰！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……빌어먹을!","JPN":"……ああもう！","ENG":"... Darn it!","TWN":"……該死！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저도 따라가겠습니다! 둘이면 그래도 혼자보다는 죽을 확률이 적겠죠!","JPN":"私も一緒に行きます！\\n二人なら一人よりは死ぬ確率が低くなるでしょう！","ENG":"I’m coming with you! I suppose two is better than one!","TWN":"我也一起去！兩個一起的話，死亡的機率起碼比一個人低吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"좌표 확인 끝났으니 격납고로 가시죠! 관리국에도 전달했습니다!","JPN":"座標確認が終わったので格納庫に行きましょう！\\n管理局にも伝えました！","ENG":"I have the coordinates, let’s go to the hangar! I called the Administration as well!","TWN":"座標確認完畢，我們去機庫吧！我也已經通知管理局！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"레나 양! 듣고 있나요? 당장 코핀 함을……!","JPN":"レナさん！　聞こえますか？　今すぐコフィン艦を……！","ENG":"Lena, are you listening? We have to ready the Coffin—","TWN":"蕾娜！你有聽到嗎？立刻將科芬艦……！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 뭔진 몰라도 꽤 바쁘신 것 같네요.","JPN":"ははは、よくわかりませんが、ずいぶんお忙しいようですね。","ENG":"Haha, you seem very busy.","TWN":"哈哈，看您似乎很忙的樣子。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그래도 모처럼 옛 제자가 방문했는데 느긋하게 차라도 한 잔 주시면 어떨까요?","JPN":"ですが、せっかくかつての弟子が訪れたんです。\\nお茶の一杯でも出してもらえませんか？","ENG":"But I’m an old apprentice of yours, Master. How about you relax a little and bring me a cup of tea?","TWN":"不過徒弟難得來拜訪，是不是好歹也給杯茶吧？"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"나유빈!","JPN":"イチノセ！","ENG":"Na Yubin!","TWN":"羅瑜斌!"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"너 미쳤어? 지금 무슨 짓을 하고 있는 거야?","JPN":"あなた、正気なの？　こんな時に何をしてるのかわかってるの？","ENG":"Are you crazy? What are you doing?","TWN":"你發什麼神經！你這在做什麼！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"글쎄? 무슨 말인지 잘 모르겠는데, 수연아?","JPN":"さあね。なんのことだかサッパリわからないな、キズナ。","ENG":"Huh? I don’t know what you’re talking about, Sooyeon.","TWN":"什麼意思？我不懂你在說什麼？"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"설령 지금 어딘가에서 무슨 일이 벌어지고 있다고 해도…….","JPN":"たとえ今どこかで何かが起こっているとしても……","ENG":"Whatever is happening in the world...","TWN":"不管現在在哪裡發生什麼事……"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그건 내가 아니라 구원기사단의 기사님들이 저지른 일이 아닐까?","JPN":"それは僕ではなく、救世騎士団のみなさんの仕業じゃないかな。","ENG":"It’s not on me. It’s the Knights of Redemption.","TWN":"都與我無關，全是救贖騎士團的人幹的好事對吧？"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"너…… 그걸 지금 말이라고……!","JPN":"あなた……冗談じゃないわ！","ENG":"You... Are you kidding me?","TWN":"你……說的還是人話……！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くっ……！","ENG":"Ngh!","TWN":"唔……！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_IMPACT"},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"스승님, 제가 연락도 없이 방문하긴 했지만 다짜고짜 칼을 휘두르는 건 조금 과격한 인사 같은데요?","JPN":"師匠、いくら僕が事前連絡もなく来てしまったとはいえ、\\nいきなり剣を振り回すのは少し過激な挨拶だと思いませんか？","ENG":"Master. I know it’s rude to show up like this without an appointment, but don’t you think swinging a sword is a bit too much?","TWN":"師父，雖然我沒先打聲招呼就跑來，但你也不用這麼熱情地招呼我吧？"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_IMPACT"},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이수연! 먼저 가겠다! 이 녀석은 네가 맡아라!","JPN":"キズナ！　先に行く！　こいつはお前に任せるぞ！","ENG":"Lee Sooyeon, I’m going first! You take care of Yubin!","TWN":"李秀妍！我先出發，這傢伙交給你！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"알겠습니다!","JPN":"承知しました！","ENG":"Understood!","TWN":"好！交給我！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"죄송하지만 스승님. 전 수연이와는 무서워서 싸우고 싶지 않거든요.","JPN":"すみませんが、師匠。キズナは怖いので戦いたくありません。","ENG":"Master, I’m sorry, but I don’t want to fight Sooyeon. She’s too scary.","TWN":"師父抱歉，我比較怕秀妍，不敢和她打。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그러니까 스승님께서 제 상대를 조금 더 해 주셔야겠어요.","JPN":"だからもう少しの間、僕の相手は師匠にしてもらいますね。","ENG":"I would rather spend some more time with you.","TWN":"要請師父委屈一下，再當一下我的對手。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그게 무슨……!","JPN":"それはどういう……！","ENG":"What are you...","TWN":"你在說……！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"저 노처녀가 정말 구 관리국의 에이스였다고? 대장과 같은?","JPN":"あの老嬢が本当に旧管理局のエース？　隊長と同じような？","ENG":"That old maid really was the ace of the Old Administration? Like our commander?","TWN":"那個老女人真的是舊管理局的王牌？和隊長一樣？"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L45_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"지수야, 너 입조심 해야 할 것 같은데?","JPN":"あのさーシノ、発言には気をつけたほうがいいかもよ。","ENG":"Jisoo, you should watch your mouth.","TWN":"智秀，你說話還是小心點吧？"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"저 아줌마 진짜로 화나면 무시무시하거든? 여기 닭살 돋은 거 안 보여?","JPN":"あのおばさん、ガチで怒ると本当に怖いんだよ？\\n今鳥肌立ったの、見える？","ENG":"That old lady can be really scary. See these goosebumps?","TWN":"那位阿姨真的生氣的時候可是很可怕的！你看我的雞皮疙瘩！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"흥. 소름이 아니라 여드름이겠지. 저리 비켜라, 원숭이.","JPN":"ふん、鳥肌じゃなくてニキビだろう。どけ、サル。","ENG":"Hah, I think they are pimples, not goosebumps. Step aside, Monkey.","TWN":"哼！那才不是什麼雞皮疙瘩，是青春痘吧？走開啦，臭猴子！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"저런 퇴물은 나 혼자 상대해도 충분해!","JPN":"あんな年代物の相手は私一人で十分だ！","ENG":"I can take care of that dud all by myself!","TWN":"前員工就交給我來對付！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어휴, 저러다 죽도록 처맞아 봐야 정신을 차리지…… 조심해!","JPN":"あーあ、調子乗って死ぬ寸前まで殴られないと気づかないんだろうなあ……\\n気をつけて！","ENG":"Geez, you have to be beaten to death before understanding—be careful!","TWN":"哀～我看你不被她揍兩下是不會清醒的……自己保重囉！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"대체 무슨 짓이냐, 나유빈!","JPN":"いったい何の真似だ、イチノセ・カオル！","ENG":"What are you doing, Na Yubin?","TWN":"羅瑜斌，你這是在做什麼！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_IMPACT"},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이건 정말로 선을 넘었어! 이대로 세상을 멸망시킬 생각이냐?","JPN":"ついに一線を越えてきたな。このまま世界を滅ぼすつもりか？","ENG":"You really are crossing the line! Do you want the world to collapse?","TWN":"你真的越界了！你是想讓這個世界滅亡嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그럴 리가요. 이래봬도 이 세계가 선택한 대적자인데요.","JPN":"まさか。こう見えて僕、この世界が選んだ敵対者ですから。","ENG":"Of course not. I am the Antagonist that the world has chosen.","TWN":"怎麼可能，再怎麼說我也是這個世界選擇的敵對者。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그럼 어째서!","JPN":"じゃあ、なぜだ！","ENG":"Then why?","TWN":"那你為何要這樣！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"전 이 세계의 잠재력을 믿고 있거든요, 스승님과 달리.","JPN":"僕はこの世界の潜在能力を信じているんですよ。師匠とは違って。","ENG":"Unlike you, I believe in this world, Master.","TWN":"我和師父不一樣，我相信這個世界的潛力。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐라고……?","JPN":"何だと……！？","ENG":"What?","TWN":"什麼意思……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"보모가 너무 오래 붙어 있으면 아이는 자랄 수 없는 법입니다.","JPN":"過保護な大人があまりに長く付きっきりだと、\\n子どもはなかなか育たないものです。","ENG":"You can’t expect a child to grow if their nanny takes care of everything for them.","TWN":"孩子如果一直黏著父母怎麼會長大呢？"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이 세상은 조금 넘어져서 다칠 필요가 있어요.","JPN":"この世界は少し転んで、ケガをする必要があります。","ENG":"This world needs some hurting.","TWN":"這個世界需要跌倒受傷，"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그래야 다시 일어나고, 더 강해질 수 있죠.","JPN":"そうして再び立ち上がることで、さらに強くなれます。","ENG":"So that it can stand back and grow stronger.","TWN":"才能再爬起來，變得更堅強。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"스승님은 동의하기 어렵겠지만요.","JPN":"師匠は同意してくれそうにありませんが。","ENG":"You may disagree, though.","TWN":"但我知道師父一定無法認同。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"닥쳐, 계속 막겠다면 힘으로 뚫고 가겠다!","JPN":"黙れ。邪魔するなら力尽くで突破する！","ENG":"Shut up, I will use force if I have to!","TWN":"閉嘴！再攔我的話，就休怪我不客氣！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하. 가능하면 살살 부탁드립니다. 스승님.","JPN":"はは。できればお手柔らかにお願いしますよ、師匠。","ENG":"Haha, okay, but go easy on me, Master.","TWN":"哈哈，那就動手試試看吧，師父。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};